-- 038_remaining_fixes.sql
-- Clean up remaining non-fatal PostgreSQL errors:
-- 1. command_subsettings id=0 duplicate key (add auto_id_on_zero trigger)
-- 2. adventure_template + adventure_template_entry missing tables
-- 3. start_zones data (proper starting positions for each race/class/deity)

BEGIN;

-- ============================================================
-- 1. command_subsettings: fix id=0 auto-increment
-- ============================================================

TRUNCATE TABLE command_subsettings;

CREATE OR REPLACE FUNCTION auto_id_on_zero()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.id = 0 THEN
        NEW.id = nextval(pg_get_serial_sequence(TG_TABLE_NAME, 'id'));
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS trg_auto_id_on_zero ON command_subsettings;
CREATE TRIGGER trg_auto_id_on_zero
    BEFORE INSERT ON command_subsettings
    FOR EACH ROW EXECUTE FUNCTION auto_id_on_zero();

-- ============================================================
-- 2. adventure_template + adventure_template_entry
-- ============================================================

CREATE TABLE IF NOT EXISTS adventure_template (
    id                  SERIAL PRIMARY KEY,
    zone                TEXT NOT NULL DEFAULT '',
    zone_version        SMALLINT NOT NULL DEFAULT 0,
    is_hard             SMALLINT NOT NULL DEFAULT 0,
    is_raid             SMALLINT NOT NULL DEFAULT 0,
    min_level           SMALLINT NOT NULL DEFAULT 1,
    max_level           SMALLINT NOT NULL DEFAULT 65,
    type                SMALLINT NOT NULL DEFAULT 0,
    type_data           INTEGER NOT NULL DEFAULT 0,
    type_count          SMALLINT NOT NULL DEFAULT 0,
    assa_x              REAL NOT NULL DEFAULT 0,
    assa_y              REAL NOT NULL DEFAULT 0,
    assa_z              REAL NOT NULL DEFAULT 0,
    assa_h              REAL NOT NULL DEFAULT 0,
    text                TEXT NOT NULL DEFAULT '',
    duration            INTEGER NOT NULL DEFAULT 7200,
    zone_in_time        INTEGER NOT NULL DEFAULT 1800,
    win_points          SMALLINT NOT NULL DEFAULT 0,
    lose_points         SMALLINT NOT NULL DEFAULT 0,
    theme               SMALLINT NOT NULL DEFAULT 0,
    zone_in_zone_id     SMALLINT NOT NULL DEFAULT 0,
    zone_in_x           REAL NOT NULL DEFAULT 0,
    zone_in_y           REAL NOT NULL DEFAULT 0,
    zone_in_object_id   SMALLINT NOT NULL DEFAULT 0,
    dest_x              REAL NOT NULL DEFAULT 0,
    dest_y              REAL NOT NULL DEFAULT 0,
    dest_z              REAL NOT NULL DEFAULT 0,
    dest_h              REAL NOT NULL DEFAULT 0,
    graveyard_zone_id   INTEGER NOT NULL DEFAULT 0,
    graveyard_x         REAL NOT NULL DEFAULT 0,
    graveyard_y         REAL NOT NULL DEFAULT 0,
    graveyard_z         REAL NOT NULL DEFAULT 0,
    graveyard_radius    TEXT NOT NULL DEFAULT '0'
);

CREATE TABLE IF NOT EXISTS adventure_template_entry (
    id                  INTEGER NOT NULL DEFAULT 0,
    template_id         INTEGER NOT NULL DEFAULT 0,
    PRIMARY KEY (id)
);

